//! Small aligned write-chain commutation refutations.
//!
//! This covers generated byte-store chains of the form "write word `x`, then
//! write word `y`" versus the reverse order, guarded by alignment facts on both
//! word addresses. For four-byte aligned words, the two address ranges are
//! either disjoint or the same range with the same byte values, so the stores
//! commute.

use axeyum_ir::{ArraySortKey, Op, Sort, TermArena, TermId, TermNode};

/// A checked refutation of a guarded aligned write-chain disequality.
#[derive(Debug, Clone, PartialEq, Eq)]
pub struct AlignedWriteChainCommutationCertificate {
    /// The original top-level assertion.
    pub assertion: TermId,
    /// Left array term from the guarded disequality.
    pub lhs_array: TermId,
    /// Right array term from the guarded disequality.
    pub rhs_array: TermId,
    /// Common base array before the two write blocks.
    pub base_array: TermId,
    /// First word/address value written.
    pub first_word: TermId,
    /// Second word/address value written.
    pub second_word: TermId,
    /// Number of byte lanes in each word write.
    pub lanes: usize,
    /// Element width of each byte lane.
    pub element_width: u32,
    /// Bit width of array indices and word addresses.
    pub index_width: u32,
}

/// Returns a certificate when the top-level conjunction contains a BV1 assertion
/// that demands two aligned write-chain permutations be unequal.
#[must_use]
pub fn aligned_write_chain_commutation_refutation(
    arena: &TermArena,
    assertions: &[TermId],
) -> Option<AlignedWriteChainCommutationCertificate> {
    let mut conjuncts = Vec::new();
    for &assertion in assertions {
        collect_top_conjuncts(arena, assertion, &mut conjuncts);
    }

    for assertion in conjuncts {
        let bit = match_negated_bv1_zero_equality(arena, assertion)?;
        let mut operands = Vec::new();
        collect_bv_and_operands(arena, bit, &mut operands);

        let mut guards = Vec::new();
        let mut disequalities = Vec::new();
        for operand in operands {
            if let Some(guard) = match_low_zero_guard(arena, operand) {
                guards.push(guard);
            }
            if let Some((lhs, rhs)) = match_array_diseq_bit(arena, operand) {
                disequalities.push((lhs, rhs));
            }
        }

        for (lhs_array, rhs_array) in disequalities {
            if let Some(cert) =
                match_commuting_write_chains(arena, assertion, lhs_array, rhs_array, &guards)
            {
                return Some(cert);
            }
            if let Some(cert) =
                match_commuting_write_chains(arena, assertion, rhs_array, lhs_array, &guards)
            {
                return Some(cert);
            }
        }
    }
    None
}

#[derive(Debug, Clone, Copy, PartialEq, Eq)]
struct LowZeroGuard {
    word: TermId,
    low_bits: u32,
}

#[derive(Debug, Clone, PartialEq, Eq)]
struct WriteBlock {
    word: TermId,
    lanes: usize,
    element_width: u32,
    index_width: u32,
}

#[derive(Debug, Clone, Copy)]
struct StoreWrite {
    index: TermId,
    value: TermId,
}

fn collect_top_conjuncts(arena: &TermArena, term: TermId, out: &mut Vec<TermId>) {
    match arena.node(term) {
        TermNode::App {
            op: Op::BoolAnd,
            args,
        } if args.len() == 2 => {
            collect_top_conjuncts(arena, args[0], out);
            collect_top_conjuncts(arena, args[1], out);
        }
        _ => out.push(term),
    }
}

fn match_negated_bv1_zero_equality(arena: &TermArena, term: TermId) -> Option<TermId> {
    let TermNode::App {
        op: Op::BoolNot,
        args,
    } = arena.node(term)
    else {
        return None;
    };
    let [inner] = &**args else {
        return None;
    };
    let TermNode::App { op: Op::Eq, args } = arena.node(*inner) else {
        return None;
    };
    let [lhs, rhs] = &**args else {
        return None;
    };
    if is_bv_const(arena, *lhs, 1, 0) && arena.sort_of(*rhs) == Sort::BitVec(1) {
        Some(*rhs)
    } else if is_bv_const(arena, *rhs, 1, 0) && arena.sort_of(*lhs) == Sort::BitVec(1) {
        Some(*lhs)
    } else {
        None
    }
}

fn collect_bv_and_operands(arena: &TermArena, term: TermId, out: &mut Vec<TermId>) {
    match arena.node(term) {
        TermNode::App {
            op: Op::BvAnd,
            args,
        } if args.len() == 2 && arena.sort_of(term) == Sort::BitVec(1) => {
            collect_bv_and_operands(arena, args[0], out);
            collect_bv_and_operands(arena, args[1], out);
        }
        _ => out.push(term),
    }
}

fn match_array_diseq_bit(arena: &TermArena, term: TermId) -> Option<(TermId, TermId)> {
    let TermNode::App {
        op: Op::BvNot,
        args,
    } = arena.node(term)
    else {
        return match_array_neq_ite(arena, term);
    };
    let [inner] = &**args else {
        return None;
    };
    match_array_eq_ite(arena, *inner)
}

fn match_array_neq_ite(arena: &TermArena, term: TermId) -> Option<(TermId, TermId)> {
    let (cond, then_term, else_term) = match_ite(arena, term)?;
    if !is_bv_const(arena, then_term, 1, 0) || !is_bv_const(arena, else_term, 1, 1) {
        return None;
    }
    match_array_eq(arena, cond)
}

fn match_array_eq_ite(arena: &TermArena, term: TermId) -> Option<(TermId, TermId)> {
    let (cond, then_term, else_term) = match_ite(arena, term)?;
    if !is_bv_const(arena, then_term, 1, 1) || !is_bv_const(arena, else_term, 1, 0) {
        return None;
    }
    match_array_eq(arena, cond)
}

fn match_array_eq(arena: &TermArena, term: TermId) -> Option<(TermId, TermId)> {
    let TermNode::App { op: Op::Eq, args } = arena.node(term) else {
        return None;
    };
    let [lhs, rhs] = &**args else {
        return None;
    };
    if matches!(arena.sort_of(*lhs), Sort::Array { .. })
        && arena.sort_of(*lhs) == arena.sort_of(*rhs)
    {
        Some((*lhs, *rhs))
    } else {
        None
    }
}

fn match_low_zero_guard(arena: &TermArena, term: TermId) -> Option<LowZeroGuard> {
    let (cond, then_term, else_term) = match_ite(arena, term)?;
    if !is_bv_const(arena, then_term, 1, 1) || !is_bv_const(arena, else_term, 1, 0) {
        return None;
    }
    let TermNode::App { op: Op::Eq, args } = arena.node(cond) else {
        return None;
    };
    let [lhs, rhs] = &**args else {
        return None;
    };
    match_low_zero_equality_side(arena, *lhs, *rhs)
        .or_else(|| match_low_zero_equality_side(arena, *rhs, *lhs))
}

fn match_low_zero_equality_side(
    arena: &TermArena,
    lhs: TermId,
    rhs: TermId,
) -> Option<LowZeroGuard> {
    let TermNode::App {
        op: Op::Extract { hi, lo },
        args,
    } = arena.node(lhs)
    else {
        return None;
    };
    let [word] = &**args else {
        return None;
    };
    if *lo != 0 || !is_bv_const(arena, rhs, hi + 1, 0) {
        return None;
    }
    Some(LowZeroGuard {
        word: *word,
        low_bits: hi + 1,
    })
}

fn match_commuting_write_chains(
    arena: &TermArena,
    assertion: TermId,
    lhs_array: TermId,
    rhs_array: TermId,
    guards: &[LowZeroGuard],
) -> Option<AlignedWriteChainCommutationCertificate> {
    let (lhs_base, lhs_writes) = store_chain(arena, lhs_array)?;
    let (rhs_base, rhs_writes) = store_chain(arena, rhs_array)?;
    if lhs_base != rhs_base || lhs_writes.len() != 8 || rhs_writes.len() != 8 {
        return None;
    }

    let lhs_first = match_write_block(arena, &lhs_writes[0..4])?;
    let lhs_second = match_write_block(arena, &lhs_writes[4..8])?;
    let rhs_first = match_write_block(arena, &rhs_writes[0..4])?;
    let rhs_second = match_write_block(arena, &rhs_writes[4..8])?;
    if lhs_first != rhs_second || lhs_second != rhs_first || lhs_first == lhs_second {
        return None;
    }
    if lhs_first.lanes != 4
        || lhs_second.lanes != 4
        || lhs_first.element_width != lhs_second.element_width
        || lhs_first.index_width != lhs_second.index_width
    {
        return None;
    }
    let alignment_bits = exact_log2(lhs_first.lanes)?;
    if !has_low_zero_guard(guards, lhs_first.word, alignment_bits)
        || !has_low_zero_guard(guards, lhs_second.word, alignment_bits)
    {
        return None;
    }
    if !array_sort_matches(
        arena,
        lhs_base,
        lhs_first.index_width,
        lhs_first.element_width,
    ) {
        return None;
    }

    Some(AlignedWriteChainCommutationCertificate {
        assertion,
        lhs_array,
        rhs_array,
        base_array: lhs_base,
        first_word: lhs_first.word,
        second_word: lhs_second.word,
        lanes: lhs_first.lanes,
        element_width: lhs_first.element_width,
        index_width: lhs_first.index_width,
    })
}

fn store_chain(arena: &TermArena, term: TermId) -> Option<(TermId, Vec<StoreWrite>)> {
    let mut current = term;
    let mut writes = Vec::new();
    loop {
        let TermNode::App {
            op: Op::Store,
            args,
        } = arena.node(current)
        else {
            writes.reverse();
            return Some((current, writes));
        };
        let [array, index, value] = &**args else {
            return None;
        };
        writes.push(StoreWrite {
            index: *index,
            value: *value,
        });
        current = *array;
    }
}

fn match_write_block(arena: &TermArena, writes: &[StoreWrite]) -> Option<WriteBlock> {
    let mut word = None;
    let mut element_width = None;
    let mut index_width = None;
    for (offset, write) in writes.iter().enumerate() {
        let offset_u32 = u32::try_from(offset).ok()?;
        let (idx_word, idx_width, idx_offset) = match_index_offset(arena, write.index)?;
        if idx_offset != offset as u128 {
            return None;
        }
        let (value_word, value_width) = match_lane_extract(arena, write.value, offset_u32)?;
        if idx_word != value_word {
            return None;
        }
        set_or_same(&mut word, idx_word)?;
        set_or_same(&mut index_width, idx_width)?;
        set_or_same(&mut element_width, value_width)?;
    }
    Some(WriteBlock {
        word: word?,
        lanes: writes.len(),
        element_width: element_width?,
        index_width: index_width?,
    })
}

fn match_index_offset(arena: &TermArena, term: TermId) -> Option<(TermId, u32, u128)> {
    let TermNode::App {
        op: Op::BvAdd,
        args,
    } = arena.node(term)
    else {
        return None;
    };
    let [lhs, rhs] = &**args else {
        return None;
    };
    match_index_offset_side(arena, *lhs, *rhs)
        .or_else(|| match_index_offset_side(arena, *rhs, *lhs))
}

fn match_index_offset_side(
    arena: &TermArena,
    offset: TermId,
    word: TermId,
) -> Option<(TermId, u32, u128)> {
    let TermNode::BvConst { width, value } = arena.node(offset) else {
        return None;
    };
    if arena.sort_of(word) != Sort::BitVec(*width) {
        return None;
    }
    Some((word, *width, *value))
}

fn match_lane_extract(arena: &TermArena, term: TermId, offset: u32) -> Option<(TermId, u32)> {
    let TermNode::App {
        op: Op::Extract { hi, lo },
        args,
    } = arena.node(term)
    else {
        return None;
    };
    let [word] = &**args else {
        return None;
    };
    let element_width = hi.checked_sub(*lo)? + 1;
    if *lo != offset.checked_mul(element_width)? {
        return None;
    }
    let Sort::BitVec(word_width) = arena.sort_of(*word) else {
        return None;
    };
    if *hi >= word_width {
        return None;
    }
    Some((*word, element_width))
}

fn set_or_same<T: Copy + Eq>(slot: &mut Option<T>, value: T) -> Option<()> {
    match *slot {
        Some(existing) if existing != value => None,
        Some(_) => Some(()),
        None => {
            *slot = Some(value);
            Some(())
        }
    }
}

fn has_low_zero_guard(guards: &[LowZeroGuard], word: TermId, low_bits: u32) -> bool {
    guards
        .iter()
        .any(|guard| guard.word == word && guard.low_bits == low_bits)
}

fn exact_log2(value: usize) -> Option<u32> {
    if value == 0 || !value.is_power_of_two() {
        None
    } else {
        Some(value.trailing_zeros())
    }
}

fn array_sort_matches(
    arena: &TermArena,
    array: TermId,
    index_width: u32,
    element_width: u32,
) -> bool {
    matches!(
        arena.sort_of(array),
        Sort::Array {
            index: ArraySortKey::BitVec(i),
            element: ArraySortKey::BitVec(e),
        } if i == index_width && e == element_width
    )
}

fn match_ite(arena: &TermArena, term: TermId) -> Option<(TermId, TermId, TermId)> {
    let TermNode::App { op: Op::Ite, args } = arena.node(term) else {
        return None;
    };
    let [cond, then_term, else_term] = &**args else {
        return None;
    };
    Some((*cond, *then_term, *else_term))
}

fn is_bv_const(arena: &TermArena, term: TermId, width: u32, value: u128) -> bool {
    matches!(
        arena.node(term),
        TermNode::BvConst { width: w, value: v } if *w == width && *v == value
    )
}

#[cfg(test)]
mod tests {
    use axeyum_smtlib::parse_script;

    use super::*;

    #[test]
    fn refutes_aligned_write_chain_commutation_regression() {
        let text = include_str!(
            "../../../corpus/public-curated/non-incremental/QF_AUFBV/bitwuzla-regress-clean/solver__array__wchains002ue.smt2"
        );
        let script = parse_script(text).expect("parse wchains002ue");
        let cert = aligned_write_chain_commutation_refutation(&script.arena, &script.assertions)
            .expect("aligned write-chain commutation refutes wchains002ue");
        assert_eq!(cert.lanes, 4);
        assert_eq!(cert.element_width, 8);
        assert_eq!(cert.index_width, 32);
    }
}
